#### 任务 2.1: WebSocket 实时数据推送
```typescript
// 位置: src/dashboard/services/realtime.service.ts
// 预计: 1 天
```

**实现内容**:
```typescript
class RealtimeService {
  // 1. 订阅管理
  subscribe(client: WebSocket, channel: string) {
    if (!this.channels.has(channel)) {
      this.channels.set(channel, new Set());
    }
    this.channels.get(channel)!.add(client);
  }

  // 2. 广播逻辑
  broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data, timestamp: Date.now() });

    for (const [channel, clients] of this.channels) {
      if (this.shouldBroadcast(channel, event)) {
        clients.forEach(client => {
          if (client.readyState === WebSocket.OPEN) {
            client.send(message);
          }
        });
      }
    }
  }

  // 3. 心跳检测
  startHeartbeat() {
    setInterval(() => {
      this.broadcast('ping', { timestamp: Date.now() });
    }, 30000);
  }
}
```

