// src/config/permission-config.ts
export enum PermissionMode {
  STRICT = 'strict',           // 严格模式：每个操作需要确认
  INTERACTIVE = 'interactive', // 交互模式：批量操作确认
  BYPASS = 'bypass'           // 绕过模式：自动确认（仅开发环境）
}

export function getPermissionMode(): PermissionMode {
  const mode = process.env.PERMISSION_MODE || 'strict';
  const isDev = process.env.NODE_ENV === 'development';

  // 生产环境强制使用严格模式
  if (!isDev && mode === 'bypass') {
    console.warn('⚠️ Bypass mode not allowed in production');
    return PermissionMode.STRICT;
  }

  return mode as PermissionMode;
}
