// src/utils/git-helper.ts
import { execSync } from 'child_process';
import { escapeShellArg } from './escape';

export function safeGitCommand(args: string[]): string {
  // 白名单允许的 Git 命令
  const allowedCommands = ['status', 'log', 'diff', 'show', 'rev-parse'];
  const command = args[0];

  if (!allowedCommands.includes(command)) {
    throw new Error(`Git command '${command}' not allowed`);
  }

  // 转义所有参数
  const safeArgs = args.map(escapeShellArg);

  try {
    return execSync(`git ${safeArgs.join(' ')}`, {
      encoding: 'utf-8',
      maxBuffer: 10 * 1024 * 1024 // 10MB
    });
  } catch (error) {
    throw new Error(`Git command failed: ${error}`);
  }
}
```

